import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Prize, PrizeCategory } from './types';
import PrizeCard from './components/PrizeCard';
import PrizeFormModal from './components/PrizeFormModal';
import PlusIcon from './components/icons/PlusIcon';
import SearchIcon from './components/icons/SearchIcon';
import PrizeList from './components/PrizeList';
import Squares2x2Icon from './components/icons/Squares2x2Icon';
import QueueListIcon from './components/icons/QueueListIcon';
import CheckCircleIcon from './components/icons/CheckCircleIcon';
import ArrowPathIcon from './components/icons/ArrowPathIcon';

const prizeCategories: PrizeCategory[] = ['マスコット', 'ぬいぐるみ', 'フィギュア', 'その他'];

type DisplayMode = 'card' | 'list';
type SortOrder = 'date-desc' | 'name-asc' | 'name-desc';

const App: React.FC = () => {
  const [prizes, setPrizes] = useState<Prize[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [prizeToEdit, setPrizeToEdit] = useState<Prize | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<PrizeCategory | 'すべて'>('すべて');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('card');
  const [sortOrder, setSortOrder] = useState<SortOrder>('date-desc');

  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');
  const saveTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    try {
      const storedPrizes = localStorage.getItem('crane-game-prizes');
      if (storedPrizes) {
        const parsedPrizes: any[] = JSON.parse(storedPrizes);
        const migratedPrizes: Prize[] = parsedPrizes.map(p => ({
          ...p,
          category: p.category || 'その他',
          quantity: p.quantity ?? 1,
        }));
        setPrizes(migratedPrizes);
      }
    } catch (error) {
      console.error("Failed to load prizes from localStorage", error);
    }
  }, []);

  useEffect(() => {
    if (saveStatus === 'idle' && prizes.length === 0) return;

    setSaveStatus('saving');

    if (saveTimeoutRef.current) window.clearTimeout(saveTimeoutRef.current);

    saveTimeoutRef.current = window.setTimeout(() => {
      try {
        localStorage.setItem('crane-game-prizes', JSON.stringify(prizes));
        setSaveStatus('saved');
        saveTimeoutRef.current = window.setTimeout(() => {
          setSaveStatus('idle');
        }, 3000);
      } catch (error) {
        console.error("Failed to save prizes to localStorage", error);
        setSaveStatus('idle');
      }
    }, 500);

    return () => {
      if (saveTimeoutRef.current) window.clearTimeout(saveTimeoutRef.current);
    };
  }, [prizes]);

  const handleOpenAddModal = useCallback(() => {
    setPrizeToEdit(null);
    setIsModalOpen(true);
  }, []);

  const handleOpenEditModal = useCallback((prize: Prize) => {
    setPrizeToEdit(prize);
    setIsModalOpen(true);
  }, []);

  const handleCloseModal = useCallback(() => {
    setIsModalOpen(false);
    setPrizeToEdit(null);
  }, []);

  const handleSavePrize = useCallback((prize: Prize) => {
    setPrizes(prevPrizes => {
      const existingIndex = prevPrizes.findIndex(p => p.id === prize.id);
      if (existingIndex > -1) {
        const newPrizes = [...prevPrizes];
        newPrizes[existingIndex] = prize;
        return newPrizes;
      }
      return [...prevPrizes, prize];
    });
  }, []);

  const handleDeletePrize = useCallback((prizeId: string) => {
    if (window.confirm('この景品を削除してもよろしいですか？')) {
      setPrizes(prevPrizes => prevPrizes.filter(p => p.id !== prizeId));
      if (prizeToEdit?.id === prizeId) {
        handleCloseModal();
      }
    }
  }, [prizeToEdit, handleCloseModal]);

  const handleQuantityChange = useCallback((prizeId: string, newQuantity: number) => {
    setPrizes(prevPrizes =>
      prevPrizes.map(p =>
        p.id === prizeId ? { ...p, quantity: newQuantity } : p
      )
    );
  }, []);

  const filteredAndSortedPrizes = useMemo(() => {
    const filtered = prizes
      .filter(prize => {
        const nameMatch = prize.name.toLowerCase().includes(searchTerm.toLowerCase());
        const categoryMatch = selectedCategory === 'すべて' || prize.category === selectedCategory;
        return nameMatch && categoryMatch;
      });

      switch (sortOrder) {
        case 'name-asc':
          return [...filtered].sort((a, b) => a.name.localeCompare(b.name, 'ja'));
        case 'name-desc':
          return [...filtered].sort((a, b) => b.name.localeCompare(a.name, 'ja'));
        case 'date-desc':
        default:
          return [...filtered].sort((a, b) => new Date(b.acquisitionDate).getTime() - new Date(a.acquisitionDate).getTime());
      }
  }, [prizes, searchTerm, selectedCategory, sortOrder]);


  return (
    <div className="min-h-screen bg-slate-100 dark:bg-slate-900 text-slate-800 dark:text-slate-200 font-sans">
      <header className="bg-white dark:bg-slate-800 shadow-md sticky top-0 z-20">
        <div className="container mx-auto px-4 py-3 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-indigo-600 dark:text-indigo-400 whitespace-nowrap">
              景品在庫
            </h1>
            <div className="flex items-center text-xs font-medium px-2 py-1 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400 transition-all duration-300">
              {saveStatus === 'saving' ? (
                <>
                  <ArrowPathIcon className="w-3 h-3 mr-1 animate-spin" />
                  保存中...
                </>
              ) : saveStatus === 'saved' ? (
                <>
                  <CheckCircleIcon className="w-3 h-3 mr-1 text-green-500" />
                  保存済み
                </>
              ) : (
                <>
                  <CheckCircleIcon className="w-3 h-3 mr-1 opacity-50" />
                  クラウド保存
                </>
              )}
            </div>
          </div>

          <div className="w-full sm:w-auto flex flex-row flex-wrap items-center justify-center sm:justify-end gap-2">
            <div className="relative flex-grow sm:flex-grow-0 sm:w-48">
              <span className="absolute inset-y-0 left-0 flex items-center pl-3">
                <SearchIcon className="h-4 w-4 text-slate-400" />
              </span>
              <input
                type="text"
                placeholder="検索..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-9 pr-4 py-1.5 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg shadow-sm placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm text-slate-900 dark:text-slate-100"
                aria-label="景品を検索"
              />
            </div>
            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value as PrizeCategory | 'すべて')}
              className="px-3 py-1.5 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm text-slate-900 dark:text-slate-100"
              aria-label="カテゴリで絞り込み"
            >
              <option value="すべて">すべて</option>
              {prizeCategories.map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
             <select
              value={sortOrder}
              onChange={(e) => setSortOrder(e.target.value as SortOrder)}
              className="px-3 py-1.5 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm text-slate-900 dark:text-slate-100"
              aria-label="並び替え"
            >
              <option value="date-desc">新しい順</option>
              <option value="name-asc">名前 A-Z</option>
              <option value="name-desc">名前 Z-A</option>
            </select>
            <div className="flex items-center bg-slate-100 dark:bg-slate-700 rounded-lg p-0.5 border border-slate-200 dark:border-slate-600">
              <button
                onClick={() => setDisplayMode('card')}
                className={`p-1.5 rounded-md transition-all ${displayMode === 'card' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400'}`}
                aria-label="カード表示"
              >
                <Squares2x2Icon className="w-4 h-4" />
              </button>
              <button
                onClick={() => setDisplayMode('list')}
                className={`p-1.5 rounded-md transition-all ${displayMode === 'list' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400'}`}
                aria-label="リスト表示"
              >
                <QueueListIcon className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 md:p-8">
        {prizes.length === 0 ? (
          <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-2xl shadow-inner border-2 border-dashed border-slate-200 dark:border-slate-700">
            <div className="mx-auto w-16 h-16 bg-indigo-100 dark:bg-indigo-900/30 rounded-full flex items-center justify-center mb-4 text-indigo-500">
              <PlusIcon className="w-8 h-8" />
            </div>
            <p className="text-xl font-semibold text-slate-700 dark:text-slate-300">まだ景品がありません</p>
            <p className="mt-2 text-slate-500 dark:text-slate-400">右下の「+」ボタンから最初の景品を追加しましょう！</p>
          </div>
        ) : filteredAndSortedPrizes.length === 0 ? (
           <div className="text-center py-20">
            <p className="text-xl text-slate-500 dark:text-slate-400">検索条件に合う景品が見つかりませんでした。</p>
          </div>
        ) : (
          <>
            {displayMode === 'card' ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredAndSortedPrizes.map(prize => (
                  <PrizeCard
                    key={prize.id}
                    prize={prize}
                    onEdit={handleOpenEditModal}
                    onDelete={handleDeletePrize}
                    onQuantityChange={handleQuantityChange}
                  />
                ))}
              </div>
            ) : (
              <PrizeList
                prizes={filteredAndSortedPrizes}
                onEdit={handleOpenEditModal}
                onDelete={handleDeletePrize}
                onQuantityChange={handleQuantityChange}
              />
            )}
          </>
        )}
      </main>

      <button
        onClick={handleOpenAddModal}
        className="fixed bottom-8 right-8 bg-indigo-600 text-white p-4 rounded-full shadow-2xl hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 focus:ring-offset-slate-100 dark:focus:ring-offset-slate-900 transition-all transform hover:scale-110 active:scale-95 z-30"
        aria-label="景品を追加"
      >
        <PlusIcon className="h-8 w-8" />
      </button>

      <PrizeFormModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        onSave={handleSavePrize}
        prizeToEdit={prizeToEdit}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Prize, PrizeCategory, Manufacturer } from '../types';

interface PrizeFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (prize: Prize) => void;
  prizeToEdit?: Prize | null;
}

const prizeCategories: PrizeCategory[] = ['マスコット', 'ぬいぐるみ', 'フィギュア', 'その他'];
const prizeManufacturers: Manufacturer[] = ['指定なし', 'バンダイナムコ', 'タイトー', 'SEGA FAVE', 'FuRyu', 'Parade', 'SK', 'その他'];

const PrizeFormModal: React.FC<PrizeFormModalProps> = ({ isOpen, onClose, onSave, prizeToEdit }) => {
  const [id, setId] = useState('');
  const [name, setName] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [acquisitionDate, setAcquisitionDate] = useState('');
  const [photo, setPhoto] = useState('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState<PrizeCategory>('その他');
  const [manufacturer, setManufacturer] = useState<Manufacturer>('指定なし');

  const modalRef = useRef<HTMLDivElement>(null);
  const isInitialMount = useRef(true);

  const triggerAutoSave = useCallback(() => {
    if (!name.trim() && !prizeToEdit) return;

    const currentPrize: Prize = {
      id: id || new Date().toISOString() + Math.random(),
      name,
      quantity,
      acquisitionDate,
      category,
      manufacturer,
      photo,
      notes,
    };
    onSave(currentPrize);
  }, [id, name, quantity, acquisitionDate, category, manufacturer, photo, notes, onSave, prizeToEdit]);

  useEffect(() => {
    if (isOpen) {
      setId(prizeToEdit?.id || '');
      setName(prizeToEdit?.name || '');
      setQuantity(prizeToEdit?.quantity || 1);
      setAcquisitionDate(prizeToEdit?.acquisitionDate || new Date().toISOString().split('T')[0]);
      setPhoto(prizeToEdit?.photo || '');
      setNotes(prizeToEdit?.notes || '');
      setCategory(prizeToEdit?.category || 'その他');
      setManufacturer(prizeToEdit?.manufacturer || '指定なし');
      isInitialMount.current = true;
    }
  }, [isOpen, prizeToEdit]);

  useEffect(() => {
    if (isInitialMount.current) {
      isInitialMount.current = false;
      return;
    }
    const timer = setTimeout(() => {
      triggerAutoSave();
    }, 300);
    return () => clearTimeout(timer);
  }, [name, quantity, acquisitionDate, category, manufacturer, photo, notes, triggerAutoSave]);

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    const handleOutsideClick = (event: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleOutsideClick);
    }
    return () => {
      document.removeEventListener('mousedown', handleOutsideClick);
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex justify-center items-center z-50 p-4">
      <div ref={modalRef} className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-6 w-full max-w-md max-h-[90vh] overflow-y-auto border border-slate-200 dark:border-slate-700">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white">
            {prizeToEdit ? '景品を編集' : '新しい景品'}
          </h2>
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="space-y-5">
          <div>
            <label htmlFor="name" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">景品名</label>
            <input
              type="text"
              id="name"
              value={name}
              placeholder="何を獲得しましたか？"
              onChange={(e) => setName(e.target.value)}
              className="block w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-xl shadow-sm placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-slate-900 dark:text-slate-100 transition-all"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="category" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">カテゴリ</label>
              <select
                id="category"
                value={category}
                onChange={(e) => setCategory(e.target.value as PrizeCategory)}
                className="block w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-slate-900 dark:text-slate-100 transition-all"
              >
                {prizeCategories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            <div>
              <label htmlFor="manufacturer" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">メーカー</label>
              <select
                id="manufacturer"
                value={manufacturer}
                onChange={(e) => setManufacturer(e.target.value as Manufacturer)}
                className="block w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-slate-900 dark:text-slate-100 transition-all"
              >
                {prizeManufacturers.map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="quantity" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">数量</label>
              <div className="flex items-center">
                <button 
                  type="button"
                  onClick={() => setQuantity(Math.max(0, quantity - 1))}
                  className="px-3 py-2 bg-slate-200 dark:bg-slate-600 rounded-l-xl hover:bg-slate-300 dark:hover:bg-slate-500 transition-colors"
                >
                  -
                </button>
                <input
                  type="number"
                  id="quantity"
                  value={quantity}
                  onChange={(e) => setQuantity(Number(e.target.value))}
                  className="block w-full py-2 bg-slate-50 dark:bg-slate-700/50 border-y border-slate-200 dark:border-slate-600 text-center focus:outline-none text-slate-900 dark:text-slate-100"
                />
                <button 
                  type="button"
                  onClick={() => setQuantity(quantity + 1)}
                  className="px-3 py-2 bg-slate-200 dark:bg-slate-600 rounded-r-xl hover:bg-slate-300 dark:hover:bg-slate-500 transition-colors"
                >
                  +
                </button>
              </div>
            </div>
            <div>
              <label htmlFor="acquisitionDate" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">獲得日</label>
              <input
                type="date"
                id="acquisitionDate"
                value={acquisitionDate}
                onChange={(e) => setAcquisitionDate(e.target.value)}
                className="block w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-slate-900 dark:text-slate-100 transition-all"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">写真</label>
            <div className="flex items-start space-x-4">
              <label className="cursor-pointer flex-shrink-0 group">
                <div className="w-24 h-24 rounded-2xl border-2 border-dashed border-slate-300 dark:border-slate-600 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-700/30 group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/20 group-hover:border-indigo-400 transition-all">
                  <svg className="w-8 h-8 text-slate-400 group-hover:text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                  <span className="text-[10px] mt-1 font-bold text-slate-400 group-hover:text-indigo-500 uppercase">追加</span>
                </div>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handlePhotoChange}
                  className="hidden"
                />
              </label>
              {photo && (
                <div className="relative group">
                  <img src={photo} alt="Preview" className="w-24 h-24 rounded-2xl object-cover shadow-md" />
                  <button 
                    onClick={() => setPhoto('')}
                    className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>

          <div>
            <label htmlFor="notes" className="block text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-1">メモ</label>
            <textarea
              id="notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={3}
              placeholder="獲得場所や苦労した点など..."
              className="block w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-slate-900 dark:text-slate-100 transition-all resize-none"
            />
          </div>

          <div className="pt-4">
            <button
              type="button"
              onClick={onClose}
              className="w-full py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 focus:outline-none focus:ring-4 focus:ring-indigo-500/50 transition-all transform active:scale-[0.98] shadow-lg shadow-indigo-500/20"
            >
              完了
            </button>
            <p className="text-center text-[10px] text-slate-400 mt-3 flex items-center justify-center uppercase tracking-widest font-bold">
              <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
              </svg>
              入力内容は自動的に保存されます
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PrizeFormModal;

import React from 'react';

const CheckCircleIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
  </svg>
);

export default CheckCircleIcon;

import React from 'react';

const ArrowPathIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
