export default SaveIcon;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Prize, PrizeCategory } from './types';
import PrizeCard from './components/PrizeCard';
import PrizeFormModal from './components/PrizeFormModal';
import PlusIcon from './components/icons/PlusIcon';
import SearchIcon from './components/icons/SearchIcon';
import PrizeList from './components/PrizeList';
import Squares2x2Icon from './components/icons/Squares2x2Icon';
import QueueListIcon from './components/icons/QueueListIcon';
import CheckCircleIcon from './components/icons/CheckCircleIcon';
import ArrowPathIcon from './components/icons/ArrowPathIcon';
import SaveIcon from './components/icons/SaveIcon';

const prizeCategories: PrizeCategory[] = ['マスコット', 'ぬいぐるみ', 'フィギュア', 'その他'];

type DisplayMode = 'card' | 'list';
type SortOrder = 'date-desc' | 'name-asc' | 'name-desc';

const App: React.FC = () => {
  const [prizes, setPrizes] = useState<Prize[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [prizeToEdit, setPrizeToEdit] = useState<Prize | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<PrizeCategory | 'すべて'>('すべて');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('card');
  const [sortOrder, setSortOrder] = useState<SortOrder>('date-desc');

  const [isDirty, setIsDirty] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Load data on mount
  useEffect(() => {
    try {
      const storedPrizes = localStorage.getItem('crane-game-prizes');
      if (storedPrizes) {
        const parsedPrizes: any[] = JSON.parse(storedPrizes);
        setPrizes(parsedPrizes);
      }
    } catch (error) {
      console.error("Failed to load prizes", error);
    }
  }, []);

  // Manual save function
  const handleSaveToStorage = useCallback(() => {
    setSaveStatus('saving');
    // Simulate a brief delay for better UX feedback
    setTimeout(() => {
      try {
        localStorage.setItem('crane-game-prizes', JSON.stringify(prizes));
        setIsDirty(false);
        setSaveStatus('saved');
        setTimeout(() => setSaveStatus('idle'), 2000);
      } catch (error) {
        alert("保存に失敗しました。容量がいっぱいの可能性があります。");
        setSaveStatus('idle');
      }
    }, 400);
  }, [prizes]);

  const handleOpenAddModal = useCallback(() => {
    setPrizeToEdit(null);
    setIsModalOpen(true);
  }, []);

  const handleOpenEditModal = useCallback((prize: Prize) => {
    setPrizeToEdit(prize);
    setIsModalOpen(true);
  }, []);

  const handleCloseModal = useCallback(() => {
    setIsModalOpen(false);
    setPrizeToEdit(null);
  }, []);

  const handleUpdatePrizes = useCallback((newPrizes: Prize[]) => {
    setPrizes(newPrizes);
    setIsDirty(true);
  }, []);

  const handleSavePrize = useCallback((prize: Prize) => {
    setPrizes(prevPrizes => {
      const existingIndex = prevPrizes.findIndex(p => p.id === prize.id);
      let nextPrizes;
      if (existingIndex > -1) {
        nextPrizes = [...prevPrizes];
        nextPrizes[existingIndex] = prize;
      } else {
        nextPrizes = [...prevPrizes, prize];
      }
      setIsDirty(true);
      return nextPrizes;
    });
  }, []);

  const handleDeletePrize = useCallback((prizeId: string) => {
    if (window.confirm('この景品を削除してもよろしいですか？')) {
      setPrizes(prevPrizes => {
        const next = prevPrizes.filter(p => p.id !== prizeId);
        setIsDirty(true);
        return next;
      });
      if (prizeToEdit?.id === prizeId) {
        handleCloseModal();
      }
    }
  }, [prizeToEdit, handleCloseModal]);

  const handleQuantityChange = useCallback((prizeId: string, newQuantity: number) => {
    setPrizes(prevPrizes => {
      const next = prevPrizes.map(p =>
        p.id === prizeId ? { ...p, quantity: newQuantity } : p
      );
      setIsDirty(true);
      return next;
    });
  }, []);

  const filteredAndSortedPrizes = useMemo(() => {
    const filtered = prizes
      .filter(prize => {
        const nameMatch = prize.name.toLowerCase().includes(searchTerm.toLowerCase());
        const categoryMatch = selectedCategory === 'すべて' || prize.category === selectedCategory;
        return nameMatch && categoryMatch;
      });

      switch (sortOrder) {
        case 'name-asc':
          return [...filtered].sort((a, b) => a.name.localeCompare(b.name, 'ja'));
        case 'name-desc':
          return [...filtered].sort((a, b) => b.name.localeCompare(a.name, 'ja'));
        case 'date-desc':
        default:
          return [...filtered].sort((a, b) => new Date(b.acquisitionDate).getTime() - new Date(a.acquisitionDate).getTime());
      }
  }, [prizes, searchTerm, selectedCategory, sortOrder]);


  return (
    <div className="min-h-screen bg-slate-100 dark:bg-slate-900 text-slate-800 dark:text-slate-200 font-sans pb-20">
      <header className="bg-white dark:bg-slate-800 shadow-lg sticky top-0 z-20 border-b border-slate-200 dark:border-slate-700">
        <div className="container mx-auto px-4 py-3">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center justify-between w-full md:w-auto gap-4">
              <h1 className="text-2xl font-black tracking-tight text-indigo-600 dark:text-indigo-400">
                景品管理
              </h1>

              <div className="flex items-center gap-2">
                {/* Save Button */}
                <button
                  onClick={handleSaveToStorage}
                  disabled={saveStatus === 'saving'}
                  className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold text-sm transition-all transform active:scale-95 shadow-md ${
                    isDirty 
                      ? 'bg-indigo-600 text-white hover:bg-indigo-700' 
                      : 'bg-slate-200 dark:bg-slate-700 text-slate-500 dark:text-slate-400'
                  }`}
                >
                  {saveStatus === 'saving' ? (
                    <ArrowPathIcon className="w-4 h-4 animate-spin" />
                  ) : saveStatus === 'saved' ? (
                    <CheckCircleIcon className="w-4 h-4 text-white" />
                  ) : (
                    <SaveIcon className="w-4 h-4" />
                  )}
                  <span>{saveStatus === 'saving' ? '保存中...' : saveStatus === 'saved' ? '完了！' : '保存する'}</span>
                </button>

                {/* Dirty Indicator for Mobile */}
                {isDirty && saveStatus === 'idle' && (
                  <span className="flex h-3 w-3 relative">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-orange-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-orange-500"></span>
                  </span>
                )}
              </div>
            </div>

            <div className="flex flex-wrap items-center justify-center gap-2 w-full md:w-auto">
              <div className="relative flex-grow md:w-48">
                <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="検索..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-4 py-2 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm"
                />
              </div>

              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value as PrizeCategory | 'すべて')}
                className="px-3 py-2 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500"
              >
                <option value="すべて">全種</option>
                {prizeCategories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>

              <div className="flex items-center bg-slate-100 dark:bg-slate-700 rounded-xl p-1">
                <button
                  onClick={() => setDisplayMode('card')}
                  className={`p-1.5 rounded-lg transition-all ${displayMode === 'card' ? 'bg-white dark:bg-slate-600 shadow text-indigo-600' : 'text-slate-400'}`}
                >
                  <Squares2x2Icon className="w-4 h-4" />
                </button>
                <button
                  onClick={() => setDisplayMode('list')}
                  className={`p-1.5 rounded-lg transition-all ${displayMode === 'list' ? 'bg-white dark:bg-slate-600 shadow text-indigo-600' : 'text-slate-400'}`}
                >
                  <QueueListIcon className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>

          {/* Subtle Status Line */}
          <div className="mt-2 flex justify-center md:justify-start">
             {isDirty ? (
               <p className="text-[10px] font-bold text-orange-500 dark:text-orange-400 uppercase tracking-widest flex items-center">
                 <span className="w-1 h-1 bg-orange-500 rounded-full mr-1.5 animate-pulse"></span>
                 未保存の変更があります
               </p>
             ) : (
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center">
                 <CheckCircleIcon className="w-3 h-3 mr-1 text-green-500" />
                 データは最新です
               </p>
             )}
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 md:p-8">
        {prizes.length === 0 ? (
          <div className="text-center py-24 bg-white dark:bg-slate-800 rounded-3xl shadow-sm border-2 border-dashed border-slate-200 dark:border-slate-700">
            <div className="mx-auto w-20 h-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-full flex items-center justify-center mb-6 text-indigo-500">
              <PlusIcon className="w-10 h-10" />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-200">在庫リストが空です</h2>
            <p className="mt-3 text-slate-500 dark:text-slate-400 max-w-xs mx-auto">
              新しく獲得した景品を右下のボタンから登録しましょう。
            </p>
          </div>
        ) : filteredAndSortedPrizes.length === 0 ? (
           <div className="text-center py-20">
            <p className="text-lg text-slate-400">該当する景品は見つかりませんでした</p>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {displayMode === 'card' ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredAndSortedPrizes.map(prize => (
                  <PrizeCard
                    key={prize.id}
                    prize={prize}
                    onEdit={handleOpenEditModal}
                    onDelete={handleDeletePrize}
                    onQuantityChange={handleQuantityChange}
                  />
                ))}
              </div>
            ) : (
              <PrizeList
                prizes={filteredAndSortedPrizes}
                onEdit={handleOpenEditModal}
                onDelete={handleDeletePrize}
                onQuantityChange={handleQuantityChange}
              />
            )}
          </div>
        )}
      </main>

      <button
        onClick={handleOpenAddModal}
        className="fixed bottom-6 right-6 bg-indigo-600 text-white p-5 rounded-2xl shadow-2xl hover:bg-indigo-700 focus:outline-none focus:ring-4 focus:ring-indigo-500/50 transition-all transform hover:scale-105 active:scale-95 z-30"
        aria-label="景品を追加"
      >
        <PlusIcon className="h-6 w-6 stroke-[3]" />
      </button>

      <PrizeFormModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        onSave={handleSavePrize}
        prizeToEdit={prizeToEdit}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Prize, PrizeCategory, Manufacturer } from '../types';

interface PrizeFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (prize: Prize) => void;
  prizeToEdit?: Prize | null;
}

const prizeCategories: PrizeCategory[] = ['マスコット', 'ぬいぐるみ', 'フィギュア', 'その他'];
const prizeManufacturers: Manufacturer[] = ['指定なし', 'バンダイナムコ', 'タイトー', 'SEGA FAVE', 'FuRyu', 'Parade', 'SK', 'その他'];

const PrizeFormModal: React.FC<PrizeFormModalProps> = ({ isOpen, onClose, onSave, prizeToEdit }) => {
  const [name, setName] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [acquisitionDate, setAcquisitionDate] = useState('');
  const [photo, setPhoto] = useState('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState<PrizeCategory>('その他');
  const [manufacturer, setManufacturer] = useState<Manufacturer>('指定なし');

  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      setName(prizeToEdit?.name || '');
      setQuantity(prizeToEdit?.quantity || 1);
      setAcquisitionDate(prizeToEdit?.acquisitionDate || new Date().toISOString().split('T')[0]);
      setPhoto(prizeToEdit?.photo || '');
      setNotes(prizeToEdit?.notes || '');
      setCategory(prizeToEdit?.category || 'その他');
      setManufacturer(prizeToEdit?.manufacturer || '指定なし');
    }
  }, [isOpen, prizeToEdit]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    const prizeData: Prize = {
      id: prizeToEdit?.id || Date.now().toString(),
      name,
      quantity,
      acquisitionDate,
      category,
      manufacturer,
      photo,
      notes,
    };
    onSave(prizeData);
    onClose();
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    const handleOutsideClick = (event: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleOutsideClick);
    }
    return () => {
      document.removeEventListener('mousedown', handleOutsideClick);
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex justify-center items-end sm:items-center z-50 p-0 sm:p-4">
      <div 
        ref={modalRef} 
        className="bg-white dark:bg-slate-800 rounded-t-3xl sm:rounded-3xl shadow-2xl p-6 w-full max-w-md max-h-[90vh] overflow-y-auto border-t sm:border border-slate-200 dark:border-slate-700 animate-in slide-in-from-bottom duration-300"
      >
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-black text-slate-800 dark:text-white">
            {prizeToEdit ? '景品情報を編集' : '新しい景品を登録'}
          </h2>
          <button 
            onClick={onClose}
            className="p-2 -mr-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label htmlFor="name" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">景品名</label>
            <input
              type="text"
              id="name"
              required
              value={name}
              placeholder="例: たまごっち ぬいぐるみ"
              onChange={(e) => setName(e.target.value)}
              className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="category" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">カテゴリ</label>
              <select
                id="category"
                value={category}
                onChange={(e) => setCategory(e.target.value as PrizeCategory)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {prizeCategories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            <div>
              <label htmlFor="manufacturer" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">メーカー</label>
              <select
                id="manufacturer"
                value={manufacturer}
                onChange={(e) => setManufacturer(e.target.value as Manufacturer)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {prizeManufacturers.map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="quantity" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">個数</label>
              <div className="flex items-center bg-slate-50 dark:bg-slate-700/50 rounded-2xl border border-slate-200 dark:border-slate-600 overflow-hidden">
                <button 
                  type="button"
                  onClick={() => setQuantity(Math.max(0, quantity - 1))}
                  className="px-4 py-3 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors font-bold"
                >
                  -
                </button>
                <input
                  type="number"
                  id="quantity"
                  value={quantity}
                  onChange={(e) => setQuantity(Number(e.target.value))}
                  className="w-full bg-transparent text-center focus:outline-none font-bold"
                />
                <button 
                  type="button"
                  onClick={() => setQuantity(quantity + 1)}
                  className="px-4 py-3 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors font-bold"
                >
                  +
                </button>
              </div>
            </div>
            <div>
              <label htmlFor="acquisitionDate" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">獲得日</label>
              <input
                type="date"
                id="acquisitionDate"
                value={acquisitionDate}
                onChange={(e) => setAcquisitionDate(e.target.value)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">写真</label>
            <div className="flex gap-4 items-center">
              <label className="cursor-pointer group flex-shrink-0">
                <div className="w-24 h-24 rounded-2xl border-2 border-dashed border-slate-300 dark:border-slate-600 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-700/30 group-hover:border-indigo-400 transition-all">
                  <PlusIcon className="w-8 h-8 text-slate-300 group-hover:text-indigo-400" />
                  <span className="text-[10px] font-bold text-slate-400 mt-1 uppercase">撮る・選ぶ</span>
                </div>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handlePhotoChange}
                  className="hidden"
                />
              </label>
              {photo && (
                <div className="relative group flex-shrink-0">
                  <img src={photo} alt="Preview" className="w-24 h-24 rounded-2xl object-cover shadow-lg border-2 border-white dark:border-slate-700" />
                  <button 
                    type="button"
                    onClick={() => setPhoto('')}
                    className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1.5 shadow-xl hover:bg-red-600 transition-colors"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>

          <div>
            <label htmlFor="notes" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">備考・メモ</label>
            <textarea
              id="notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={3}
              placeholder="獲得した店舗やコツなど..."
              className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
            />
          </div>

          <div className="pt-4 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 py-4 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold rounded-2xl hover:bg-slate-200 transition-all"
            >
              キャンセル
            </button>
            <button
              type="submit"
              className="flex-[2] py-4 bg-indigo-600 text-white font-black rounded-2xl hover:bg-indigo-700 shadow-xl shadow-indigo-500/30 transition-all transform active:scale-[0.98]"
            >
              リストに追加
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PrizeFormModal;

import React from 'react';

