  const [marketPrice, setMarketPrice] = useState<string>('');
  const [photo, setPhoto] = useState('');
  const [isProcessingImage, setIsProcessingImage] = useState(false);
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState<PrizeCategory>('その他');
  const [manufacturer, setManufacturer] = useState<Manufacturer>('指定なし');

  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      setName(prizeToEdit?.name || '');
      setQuantity(prizeToEdit?.quantity || 1);
      setAcquisitionDate(prizeToEdit?.acquisitionDate || new Date().toISOString().split('T')[0]);
      setPhoto(prizeToEdit?.photo || '');
      setNotes(prizeToEdit?.notes || '');
      setCategory(prizeToEdit?.category || 'その他');
      setManufacturer(prizeToEdit?.manufacturer || '指定なし');

      const latestPrice = prizeToEdit?.priceHistory && prizeToEdit.priceHistory.length > 0
        ? prizeToEdit.priceHistory[prizeToEdit.priceHistory.length - 1].price.toString()
        : '';
      setMarketPrice(latestPrice);
    }
  }, [isOpen, prizeToEdit]);

  const resizeImage = (base64Str: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 500;
        const MAX_HEIGHT = 500;
        let width = img.width;
        let height = img.height;

        if (width > height) {
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
        } else {
          if (height > MAX_HEIGHT) {
            width *= MAX_HEIGHT / height;
            height = MAX_HEIGHT;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        const resizedBase64 = canvas.toDataURL('image/jpeg', 0.6);
        resolve(resizedBase64);
      };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || isProcessingImage) return;

    let updatedHistory = [...(prizeToEdit?.priceHistory || [])];
    const numericPrice = marketPrice ? parseInt(marketPrice) : 0;
    const today = new Date().toISOString().split('T')[0];

    // 価格に入力があり、前回の価格と異なる場合のみ履歴に追加
    const lastRecord = updatedHistory[updatedHistory.length - 1];
    if (numericPrice > 0 && (!lastRecord || lastRecord.price !== numericPrice)) {
      // 同じ日付の記録があれば上書き、なければ新規追加
      if (lastRecord && lastRecord.date === today) {
        updatedHistory[updatedHistory.length - 1] = { date: today, price: numericPrice };
      } else {
        updatedHistory.push({ date: today, price: numericPrice });
      }
    }

    const prizeData: Prize = {
      id: prizeToEdit?.id || Date.now().toString(),
      name,
      quantity,
      acquisitionDate,
      category,
      manufacturer,
      photo,
      notes,
      priceHistory: updatedHistory
    };
    onSave(prizeData);
    onClose();
  };

  const handlePhotoChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsProcessingImage(true);
      const file = e.target.files[0];
      const reader = new FileReader();

      reader.onloadend = async () => {
        const base64 = reader.result as string;
        try {
          const compressed = await resizeImage(base64);
          setPhoto(compressed);
        } catch (err) {
          console.error("Image processing failed", err);
          setPhoto(base64); 
        } finally {
          setIsProcessingImage(false);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    const handleOutsideClick = (event: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleOutsideClick);
    }
    return () => {
      document.removeEventListener('mousedown', handleOutsideClick);
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex justify-center items-end sm:items-center z-50 p-0 sm:p-4">
      <div 
        ref={modalRef} 
        className="bg-white dark:bg-slate-800 rounded-t-3xl sm:rounded-3xl shadow-2xl p-6 w-full max-w-md max-h-[90vh] overflow-y-auto border-t sm:border border-slate-200 dark:border-slate-700 animate-in slide-in-from-bottom duration-300"
      >
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-black text-slate-800 dark:text-white">
            {prizeToEdit ? '景品情報を編集' : '新しい景品を登録'}
          </h2>
          <button 
            onClick={onClose}
            className="p-2 -mr-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label htmlFor="name" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">景品名</label>
            <input
              type="text"
              id="name"
              required
              value={name}
              placeholder="例: たまごっち ぬいぐるみ"
              onChange={(e) => setName(e.target.value)}
              className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="category" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">カテゴリ</label>
              <select
                id="category"
                value={category}
                onChange={(e) => setCategory(e.target.value as PrizeCategory)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {prizeCategories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            <div>
              <label htmlFor="marketPrice" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">現在の相場 (円)</label>
              <input
                type="number"
                id="marketPrice"
                value={marketPrice}
                placeholder="例: 1500"
                onChange={(e) => setMarketPrice(e.target.value)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label htmlFor="manufacturer" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">メーカー</label>
              <select
                id="manufacturer"
                value={manufacturer}
                onChange={(e) => setManufacturer(e.target.value as Manufacturer)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {prizeManufacturers.map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
            </div>
            <div>
              <label htmlFor="acquisitionDate" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">獲得日</label>
              <input
                type="date"
                id="acquisitionDate"
                value={acquisitionDate}
                onChange={(e) => setAcquisitionDate(e.target.value)}
                className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
              />
            </div>
          </div>

          <div>
             <label htmlFor="quantity" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">在庫個数</label>
              <div className="flex items-center bg-slate-50 dark:bg-slate-700/50 rounded-2xl border border-slate-200 dark:border-slate-600 overflow-hidden w-32">
                <button 
                  type="button"
                  onClick={() => setQuantity(Math.max(0, quantity - 1))}
                  className="px-4 py-3 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors font-bold"
                >
                  -
                </button>
                <input
                  type="number"
                  id="quantity"
                  value={quantity}
                  onChange={(e) => setQuantity(Number(e.target.value))}
                  className="w-full bg-transparent text-center focus:outline-none font-bold"
                />
                <button 
                  type="button"
                  onClick={() => setQuantity(quantity + 1)}
                  className="px-4 py-3 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors font-bold"
                >
                  +
                </button>
              </div>
          </div>

          <div>
            <label className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">
              写真 {isProcessingImage && <span className="text-indigo-500 normal-case font-bold animate-pulse ml-2">圧縮中...</span>}
            </label>
            <div className="flex gap-4 items-center">
              <label className={`cursor-pointer group flex-shrink-0 ${isProcessingImage ? 'opacity-50 pointer-events-none' : ''}`}>
                <div className="w-24 h-24 rounded-2xl border-2 border-dashed border-slate-300 dark:border-slate-600 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-700/30 group-hover:border-indigo-400 transition-all">
                  <PlusIcon className="w-8 h-8 text-slate-300 group-hover:text-indigo-400" />
                  <span className="text-[10px] font-bold text-slate-400 mt-1 uppercase">撮る・選ぶ</span>
                </div>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handlePhotoChange}
                  className="hidden"
                />
              </label>
              {photo && (
                <div className="relative group flex-shrink-0">
                  <img src={photo} alt="Preview" className="w-24 h-24 rounded-2xl object-cover shadow-lg border-2 border-white dark:border-slate-700" />
                  <button 
                    type="button"
                    onClick={() => setPhoto('')}
                    className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1.5 shadow-xl hover:bg-red-600 transition-colors"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>

          <div>
            <label htmlFor="notes" className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-1.5 ml-1">備考・メモ</label>
            <textarea
              id="notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={3}
              placeholder="獲得した店舗やコツなど..."
              className="block w-full px-4 py-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
            />
          </div>

          <div className="pt-4 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 py-4 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold rounded-2xl hover:bg-slate-200 transition-all"
            >
              キャンセル
            </button>
            <button
              type="submit"
              disabled={isProcessingImage}
              className={`flex-[2] py-4 text-white font-black rounded-2xl shadow-xl transition-all transform active:scale-[0.98] ${isProcessingImage ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-500/30'}`}
            >
              {prizeToEdit ? '更新する' : 'リストに追加'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PrizeFormModal;

import React, { useMemo } from 'react';
import { Prize } from '../types';
import PencilIcon from './icons/PencilIcon';
import TrashIcon from './icons/TrashIcon';
import ImageIcon from './icons/ImageIcon';
import ChartBarIcon from './icons/ChartBarIcon';

interface PrizeCardProps {
  prize: Prize;
  onEdit: (prize: Prize) => void;
  onDelete: (prizeId: string) => void;
  onQuantityChange: (prizeId: string, newQuantity: number) => void;
  onShowHistory?: (prize: Prize) => void;
}

const PrizeCard: React.FC<PrizeCardProps> = ({ prize, onEdit, onDelete, onQuantityChange, onShowHistory }) => {
  const priceInfo = useMemo(() => {
    if (!prize.priceHistory || prize.priceHistory.length === 0) return null;

    const history = prize.priceHistory;
    const current = history[history.length - 1].price;
    const previous = history.length > 1 ? history[history.length - 2].price : current;
    const diff = current - previous;

    return { current, previous, diff };
  }, [prize.priceHistory]);

  return (
    <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none overflow-hidden group hover:-translate-y-1 transition-all duration-300 border border-slate-100 dark:border-slate-700">
      <div className="relative aspect-[4/3] overflow-hidden">
        {prize.photo ? (
          <img src={prize.photo} alt={prize.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
        ) : (
          <div className="w-full h-full bg-slate-50 dark:bg-slate-700/50 flex items-center justify-center">
            <ImageIcon className="w-12 h-12 text-slate-200 dark:text-slate-600" />
          </div>
        )}
        <div className="absolute top-4 left-4 flex gap-2">
           <span className="bg-white/90 dark:bg-slate-800/90 backdrop-blur px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider shadow-sm border border-slate-100 dark:border-slate-700">
            {prize.category}
          </span>
        </div>
      </div>

      <div className="p-5">
        <h3 className="text-lg font-black text-slate-800 dark:text-white mb-4 line-clamp-1">{prize.name}</h3>

        <div className="space-y-3">
          {/* Market Price Display */}
          <div className="flex items-center justify-between">
             <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">現在の相場</span>
                <div className="flex items-center gap-1.5">
                   <span className="text-xl font-black text-slate-800 dark:text-white">
                     {priceInfo ? `¥${priceInfo.current.toLocaleString()}` : '---'}
                   </span>
                   {priceInfo && priceInfo.diff !== 0 && (
                     <span className={`text-[10px] font-black px-1.5 py-0.5 rounded-md ${priceInfo.diff > 0 ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-blue-500'}`}>
                       {priceInfo.diff > 0 ? `+${priceInfo.diff}` : priceInfo.diff}
                     </span>
                   )}
                </div>
             </div>
             {prize.priceHistory && prize.priceHistory.length > 1 && (
               <button 
                 onClick={() => onShowHistory?.(prize)}
                 className="p-2 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 rounded-xl hover:bg-indigo-100 transition-colors"
                 title="相場履歴を見る"
               >
                 <ChartBarIcon className="w-5 h-5" />
               </button>
             )}
          </div>

          <div className="h-px bg-slate-50 dark:bg-slate-700/50"></div>

          <div className="flex items-center justify-between">
            <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">在庫数</span>
            <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-700/50 px-3 py-1.5 rounded-2xl">
              <button 
                onClick={() => onQuantityChange(prize.id, Math.max(0, prize.quantity - 1))}
                className="w-6 h-6 flex items-center justify-center text-slate-400 hover:text-slate-800 dark:hover:text-white transition-colors"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M20 12H4" /></svg>
              </button>
              <span className="text-sm font-black text-slate-800 dark:text-white w-4 text-center">{prize.quantity}</span>
              <button 
                onClick={() => onQuantityChange(prize.id, prize.quantity + 1)}
                className="w-6 h-6 flex items-center justify-center text-slate-400 hover:text-slate-800 dark:hover:text-white transition-colors"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
              </button>
            </div>
          </div>
        </div>

        <div className="mt-4 flex gap-2">
          <button
            onClick={() => onEdit(prize)}
            className="flex-1 py-2.5 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-xl text-xs font-black hover:bg-slate-200 transition-all flex items-center justify-center gap-2"
          >
            <PencilIcon className="w-4 h-4" /> 編集
          </button>
          <button
            onClick={() => onDelete(prize.id)}
            className="w-12 h-10 bg-slate-50 dark:bg-slate-700/50 text-slate-300 hover:text-red-500 rounded-xl flex items-center justify-center transition-all"
          >
            <TrashIcon className="w-5 h-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default PrizeCard;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Prize, PrizeCategory } from './types';
import PrizeCard from './components/PrizeCard';
import PrizeFormModal from './components/PrizeFormModal';
import PlusIcon from './components/icons/PlusIcon';
import SearchIcon from './components/icons/SearchIcon';
import PrizeList from './components/PrizeList';
import Squares2x2Icon from './components/icons/Squares2x2Icon';
import QueueListIcon from './components/icons/QueueListIcon';
import CheckCircleIcon from './components/icons/CheckCircleIcon';
import ArrowPathIcon from './components/icons/ArrowPathIcon';
import SaveIcon from './components/icons/SaveIcon';
import CogIcon from './components/icons/CogIcon';
import ArrowDownTrayIcon from './components/icons/ArrowDownTrayIcon';
import ArrowUpTrayIcon from './components/icons/ArrowUpTrayIcon';
import TrashIcon from './components/icons/TrashIcon';
import { StorageService } from './services/storage';
import PriceHistoryChart from './components/PriceHistoryChart';

const prizeCategories: PrizeCategory[] = ['マスコット', 'ぬいぐるみ', 'フィギュア', 'その他'];

type DisplayMode = 'card' | 'list';
type SortOrder = 'date-desc' | 'name-asc' | 'name-desc';

const App: React.FC = () => {
  const [prizes, setPrizes] = useState<Prize[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [prizeToEdit, setPrizeToEdit] = useState<Prize | null>(null);
  const [historyPrize, setHistoryPrize] = useState<Prize | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<PrizeCategory | 'すべて'>('すべて');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('card');
  const [sortOrder, setSortOrder] = useState<SortOrder>('date-desc');

  const [isDirty, setIsDirty] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');
  const [showTools, setShowTools] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load data from IndexedDB
  useEffect(() => {
    const initData = async () => {
      try {
        let data = await StorageService.loadPrizes();
        if (data.length === 0) {
          const oldData = StorageService.getLocalStorageData();
          if (oldData && oldData.length > 0) {
            await StorageService.savePrizes(oldData);
            data = oldData;
          }
        }
        setPrizes(data);
      } catch (error) {
        console.error("Failed to load prizes", error);
      }
    };
    initData();
  }, []);

  const handleSaveToStorage = useCallback(async () => {
    setSaveStatus('saving');
    try {
      await StorageService.savePrizes(prizes);
      setIsDirty(false);
      setSaveStatus('saved');
      setTimeout(() => setSaveStatus('idle'), 2000);
    } catch (error) {
      console.error("Storage error:", error);
      alert("保存に失敗しました。");
      setSaveStatus('idle');
    }
  }, [prizes]);

  const handleSavePrize = useCallback((prize: Prize) => {
    setPrizes(prevPrizes => {
      const existingIndex = prevPrizes.findIndex(p => p.id === prize.id);
      let nextPrizes;
      if (existingIndex > -1) {
        nextPrizes = [...prevPrizes];
        nextPrizes[existingIndex] = prize;
      } else {
        nextPrizes = [...prevPrizes, prize];
      }
      setIsDirty(true);
      return nextPrizes;
    });
  }, []);

  const handleDeletePrize = useCallback((prizeId: string) => {
    if (confirm('この景品を削除してもよろしいですか？')) {
      setPrizes(prevPrizes => {
        const next = prevPrizes.filter(p => p.id !== prizeId);
        setIsDirty(true);
        return next;
      });
    }
  }, []);

  const handleQuantityChange = useCallback((prizeId: string, newQuantity: number) => {
    setPrizes(prevPrizes => {
      const next = prevPrizes.map(p =>
        p.id === prizeId ? { ...p, quantity: newQuantity } : p
      );
      setIsDirty(true);
      return next;
    });
  }, []);

  const stats = useMemo(() => {
    const totalTypes = prizes.length;
    const totalQuantity = prizes.reduce((sum, p) => sum + p.quantity, 0);
    const categoryCount = prizes.reduce((acc, p) => {
      acc[p.category] = (acc[p.category] || 0) + p.quantity;
      return acc;
    }, {} as Record<string, number>);

    // 総資産（相場 × 数量）
    const totalValue = prizes.reduce((sum, p) => {
      const latestPrice = p.priceHistory && p.priceHistory.length > 0
        ? p.priceHistory[p.priceHistory.length - 1].price
        : 0;
      return sum + (latestPrice * p.quantity);
    }, 0);

    return { totalTypes, totalQuantity, categoryCount, totalValue };
  }, [prizes]);

  const filteredAndSortedPrizes = useMemo(() => {
    const filtered = prizes
      .filter(prize => {
        const nameMatch = prize.name.toLowerCase().includes(searchTerm.toLowerCase());
        const categoryMatch = selectedCategory === 'すべて' || prize.category === selectedCategory;
        return nameMatch && categoryMatch;
      });

      switch (sortOrder) {
        case 'name-asc':
          return [...filtered].sort((a, b) => a.name.localeCompare(b.name, 'ja'));
        case 'name-desc':
          return [...filtered].sort((a, b) => b.name.localeCompare(a.name, 'ja'));
        case 'date-desc':
        default:
          return [...filtered].sort((a, b) => new Date(b.acquisitionDate).getTime() - new Date(a.acquisitionDate).getTime());
      }
  }, [prizes, searchTerm, selectedCategory, sortOrder]);


  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-800 dark:text-slate-200 font-sans pb-24">
      <input type="file" ref={fileInputRef} onChange={() => {}} accept=".json" className="hidden" />

      <header className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-md sticky top-0 z-20 border-b border-slate-100 dark:border-slate-700">
        <div className="container mx-auto px-4 py-3">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center justify-between w-full md:w-auto gap-4">
              <h1 className="text-2xl font-black tracking-tighter text-slate-800 dark:text-white">
                CRANE<span className="text-indigo-600">STOCK</span>
              </h1>

              <div className="flex items-center gap-2">
                <button
                  onClick={handleSaveToStorage}
                  disabled={saveStatus === 'saving'}
                  className={`flex items-center gap-2 px-4 py-2 rounded-full font-black text-xs transition-all ${
                    isDirty 
                      ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                      : 'bg-slate-100 dark:bg-slate-700 text-slate-400'
                  }`}
                >
                  {saveStatus === 'saving' ? <ArrowPathIcon className="w-3 h-3 animate-spin" /> : <SaveIcon className="w-3 h-3" />}
                  {saveStatus === 'saving' ? '保存中' : saveStatus === 'saved' ? '保存完了' : '変更を保存'}
                </button>
                <button onClick={() => setShowTools(!showTools)} className="p-2 bg-slate-50 dark:bg-slate-700 rounded-full">
                  <CogIcon className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="flex items-center gap-2 w-full md:w-auto">
              <div className="relative flex-grow">
                <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="検索..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-4 py-2 bg-slate-100 dark:bg-slate-700 border-none rounded-2xl text-sm"
                />
              </div>
              <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-2xl">
                <button onClick={() => setDisplayMode('card')} className={`p-1.5 rounded-xl ${displayMode === 'card' ? 'bg-white dark:bg-slate-600 shadow-sm' : ''}`}><Squares2x2Icon className="w-4 h-4" /></button>
                <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-xl ${displayMode === 'list' ? 'bg-white dark:bg-slate-600 shadow-sm' : ''}`}><QueueListIcon className="w-4 h-4" /></button>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-6">
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <div className="bg-white dark:bg-slate-800 p-5 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-1">コレクション価値</p>
            <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">¥{stats.totalValue.toLocaleString()}</p>
          </div>
          <div className="bg-white dark:bg-slate-800 p-5 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-1">総在庫数</p>
            <p className="text-2xl font-black text-slate-800 dark:text-white">{stats.totalQuantity} <span className="text-sm font-normal text-slate-500">個</span></p>
          </div>
          <div className="col-span-2 bg-indigo-600 p-5 rounded-3xl shadow-xl shadow-indigo-100 dark:shadow-none text-white overflow-hidden relative">
            <div className="relative z-10">
              <p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-2 text-indigo-100">カテゴリ分布</p>
              <div className="flex flex-wrap gap-2">
                {prizeCategories.map(cat => (
                  <div key={cat} className="bg-white/10 backdrop-blur px-2 py-1 rounded-lg text-xs font-bold">
                    {cat}: {stats.categoryCount[cat] || 0}
                  </div>
                ))}
              </div>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-10 -mt-10 blur-2xl"></div>
          </div>
        </div>

        {prizes.length === 0 ? (
          <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-[2.5rem] border border-slate-100 dark:border-slate-700">
             <PlusIcon className="w-12 h-12 mx-auto text-slate-200 mb-4" />
             <h2 className="text-xl font-black">アイテムがありません</h2>
             <p className="text-slate-400 text-sm mt-1">右下の「+」ボタンから最初の景品を追加しましょう</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredAndSortedPrizes.map(prize => (
              <PrizeCard
                key={prize.id}
                prize={prize}
                onEdit={(p) => { setPrizeToEdit(p); setIsModalOpen(true); }}
                onDelete={handleDeletePrize}
                onQuantityChange={handleQuantityChange}
                onShowHistory={(p) => setHistoryPrize(p)}
              />
            ))}
          </div>
        )}
      </main>

      <button
        onClick={() => { setPrizeToEdit(null); setIsModalOpen(true); }}
        className="fixed bottom-8 right-8 bg-indigo-600 text-white p-5 rounded-3xl shadow-2xl shadow-indigo-300 transform transition-all hover:scale-110 active:scale-95 z-30"
      >
        <PlusIcon className="h-6 w-6 stroke-[3]" />
      </button>

      {/* History Modal */}
      {historyPrize && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-800 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-xl font-black text-slate-800 dark:text-white">{historyPrize.name}</h3>
                <p className="text-xs font-bold text-slate-400 mt-1">相場推移グラフ</p>
              </div>
              <button onClick={() => setHistoryPrize(null)} className="p-2 bg-slate-100 dark:bg-slate-700 rounded-full">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <PriceHistoryChart history={historyPrize.priceHistory || []} height={220} />

            <div className="mt-8 space-y-3 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
               {(historyPrize.priceHistory || []).slice().reverse().map((record, i) => (
                 <div key={i} className="flex justify-between items-center py-3 border-b border-slate-50 dark:border-slate-700/50">
                    <span className="text-xs font-bold text-slate-500">{record.date}</span>
                    <span className="text-sm font-black text-slate-800 dark:text-white">¥{record.price.toLocaleString()}</span>
                 </div>
               ))}
            </div>
          </div>
        </div>
      )}

      <PrizeFormModal
        isOpen={isModalOpen}
        onClose={() => { setIsModalOpen(false); setPrizeToEdit(null); }}
        onSave={handleSavePrize}
        prizeToEdit={prizeToEdit}
      />
    </div>
  );
};

export default App;
